+//! Checkpoint System for GPT-2 Training
+//!
+//! Saves and restores training state including:
+//! - BF16 model weights (~248 MB)
+//! - FP32 optimizer states (m, v for AdamW, ~1 GB)
+//! - Training metadata (step, tokens, epoch)
+//!
+//! File Format (ZELLCKPT v1):
+//! ┌─────────────────────────────────────────┐
+//! │ Magic: "ZELLCKPT" (8 bytes)             │
+//! │ Version: u64 (8 bytes)                  │
+//! │ Step: u64 (8 bytes)                     │
+//! │ Total Tokens: u64 (8 bytes)             │
+//! │ Epoch: u32 (4 bytes)                    │
+//! │ Accum Step: u32 (4 bytes)               │
+//! │ Config Hash: u64 (8 bytes)              │
+//! │ Reserved: 16 bytes                      │
+//! ├─────────────────────────────────────────┤
+//! │ Model Weights Section                   │
+//! │ - wte: [vocab * embd] BF16              │
+//! │ - wpe: [ctx * embd] BF16                │
+//! │ - ln_f_gamma, ln_f_beta                 │
+//! │ - lm_head                               │
+//! │ - Per-layer weights                     │
+//! ├─────────────────────────────────────────┤
+//! │ Optimizer State Section                 │
+//! │ - m (first moment) FP32                 │
+//! │ - v (second moment) FP32                │
+//! └─────────────────────────────────────────┘
+
+const std = @import("std");
+const trainer = @import("trainer.zig");
+const metal = @import("metal/metal_engine.zig");
+const bf16 = @import("metal/bf16_utils.zig");
+const log = std.log.scoped(.checkpoint);
+
+/// Checkpoint file magic
+pub const MAGIC: *const [8]u8 = "ZELLCKPT";
+
+/// Current checkpoint version
+pub const VERSION: u64 = 1;
+
+/// Header size (64 bytes, aligned)
+pub const HEADER_SIZE: usize = 64;
+
+/// Checkpoint header structure
+pub const CheckpointHeader = extern struct {
+    magic: [8]u8,
+    version: u64,
+    step: u64,
+    total_tokens: u64,
+    epoch: u32,
+    accum_step: u32,
+    config_hash: u64,
+    reserved: [16]u8,
+};
+
+/// Checkpointer for saving and loading training state
+pub const Checkpointer = struct {
+    base_path: []const u8,
+    allocator: std.mem.Allocator,
+    keep_last_n: u32,
+
+    // Checkpoint history for cleanup
+    checkpoints: std.ArrayList(CheckpointInfo),
+
+    const Self = @This();
+
+    const CheckpointInfo = struct {
+        step: u64,
+        path: []const u8,
+        size: u64,
+    };
+
+    /// Initialize checkpointer
+    pub fn init(allocator: std.mem.Allocator, base_path: []const u8, keep_last_n: u32) !Self {
+        // Create checkpoint directory if it doesn't exist
+        std.fs.cwd().makePath(base_path) catch |err| {
+            if (err != error.PathAlreadyExists) {
+                log.err("Failed to create checkpoint directory: {s}", .{base_path});
+                return err;
+            }
+        };
+
+        return Self{
+            .base_path = base_path,
+            .allocator = allocator,
+            .keep_last_n = keep_last_n,
+            .checkpoints = std.ArrayList(CheckpointInfo).init(allocator),
+        };
+    }
+
+    /// Save a checkpoint
+    pub fn save(self: *Self, t: *trainer.MetalTrainer) !void {
+        const step = t.step;
+        const path = try std.fmt.allocPrint(self.allocator, "{s}/ckpt_{d:0>8}.bin", .{
+            self.base_path,
+            step,
+        });
+        errdefer self.allocator.free(path);
+
+        log.info("Saving checkpoint to {s}...", .{path});
+
+        const file = try std.fs.cwd().createFile(path, .{});
+        defer file.close();
+
+        var buffered = std.io.bufferedWriter(file.writer());
+        const writer = buffered.writer();
+
+        // Write header
+        const header = CheckpointHeader{
+            .magic = MAGIC.*,
+            .version = VERSION,
+            .step = step,
+            .total_tokens = t.total_tokens,
+            .epoch = 0, // TODO: track epoch
+            .accum_step = @intCast(t.accum_step),
+            .config_hash = computeConfigHash(&t.config),
+            .reserved = [_]u8{0} ** 16,
+        };
+        try writer.writeAll(std.mem.asBytes(&header));
+
+        // Write model weights
+        try self.writeModelWeights(writer, &t.model);
+
+        // Write optimizer state
+        try self.writeOptimizerState(writer, &t.opt_state);
+
+        try buffered.flush();
+
+        // Get file size
+        const stat = try file.stat();
+        const size_mb = stat.size / (1024 * 1024);
+
+        log.info("Checkpoint saved: step={d}, tokens={d}, size={d}MB", .{
+            step,
+            t.total_tokens,
+            size_mb,
+        });
+
+        // Track checkpoint for cleanup
+        try self.checkpoints.append(.{
+            .step = step,
+            .path = path,
+            .size = stat.size,
+        });
+
+        // Cleanup old checkpoints
+        try self.cleanupOldCheckpoints();
+    }
+
+    /// Write model weights to checkpoint
+    fn writeModelWeights(self: *Self, writer: anytype, model: *const trainer.GPT2State) !void {
+        _ = self;
+
+        // Embeddings
+        try writeBuffer(writer, model.wte);
+        try writeBuffer(writer, model.wpe);
+
+        // Final layer norm
+        try writeBuffer(writer, model.ln_f_gamma);
+        try writeBuffer(writer, model.ln_f_beta);
+
+        // LM head
+        try writeBuffer(writer, model.lm_head);
+
+        // Per-layer weights
+        for (model.layers) |layer| {
+            // Attention
+            try writeBuffer(writer, layer.ln1_gamma);
+            try writeBuffer(writer, layer.ln1_beta);
+            try writeBuffer(writer, layer.Wqkv);
+            try writeBuffer(writer, layer.bias_qkv);
+            try writeBuffer(writer, layer.Wo);
+            try writeBuffer(writer, layer.bias_o);
+
+            // FFN
+            try writeBuffer(writer, layer.ln2_gamma);
+            try writeBuffer(writer, layer.ln2_beta);
+            try writeBuffer(writer, layer.Wfc);
+            try writeBuffer(writer, layer.bias_fc);
+            try writeBuffer(writer, layer.Wproj);
+            try writeBuffer(writer, layer.bias_proj);
+        }
+    }
+
+    /// Write optimizer state to checkpoint
+    fn writeOptimizerState(self: *Self, writer: anytype, opt: *const trainer.AdamWState) !void {
+        _ = self;
+
+        // Embedding optimizer state
+        try writeBuffer(writer, opt.wte_m);
+        try writeBuffer(writer, opt.wte_v);
+        try writeBuffer(writer, opt.wpe_m);
+        try writeBuffer(writer, opt.wpe_v);
+
+        // Final LN optimizer state
+        try writeBuffer(writer, opt.ln_f_gamma_m);
+        try writeBuffer(writer, opt.ln_f_gamma_v);
+        try writeBuffer(writer, opt.ln_f_beta_m);
+        try writeBuffer(writer, opt.ln_f_beta_v);
+
+        // LM head optimizer state
+        try writeBuffer(writer, opt.lm_head_m);
+        try writeBuffer(writer, opt.lm_head_v);
+
+        // Per-layer optimizer state
+        for (opt.layers) |layer| {
+            // LN1
+            try writeBuffer(writer, layer.ln1_gamma_m);
+            try writeBuffer(writer, layer.ln1_gamma_v);
+            try writeBuffer(writer, layer.ln1_beta_m);
+            try writeBuffer(writer, layer.ln1_beta_v);
+
+            // Attention
+            try writeBuffer(writer, layer.Wqkv_m);
+            try writeBuffer(writer, layer.Wqkv_v);
+            try writeBuffer(writer, layer.bias_qkv_m);
+            try writeBuffer(writer, layer.bias_qkv_v);
+            try writeBuffer(writer, layer.Wo_m);
+            try writeBuffer(writer, layer.Wo_v);
+            try writeBuffer(writer, layer.bias_o_m);
+            try writeBuffer(writer, layer.bias_o_v);
+
+            // LN2
+            try writeBuffer(writer, layer.ln2_gamma_m);
+            try writeBuffer(writer, layer.ln2_gamma_v);
+            try writeBuffer(writer, layer.ln2_beta_m);
+            try writeBuffer(writer, layer.ln2_beta_v);
+
+            // FFN
+            try writeBuffer(writer, layer.Wfc_m);
+            try writeBuffer(writer, layer.Wfc_v);
+            try writeBuffer(writer, layer.bias_fc_m);
+            try writeBuffer(writer, layer.bias_fc_v);
+            try writeBuffer(writer, layer.Wproj_m);
+            try writeBuffer(writer, layer.Wproj_v);
+            try writeBuffer(writer, layer.bias_proj_m);
+            try writeBuffer(writer, layer.bias_proj_v);
+        }
+    }
+
+    /// Load the most recent checkpoint
+    pub fn loadLatest(self: *Self, t: *trainer.MetalTrainer) !bool {
+        // Find the latest checkpoint
+        var dir = std.fs.cwd().openDir(self.base_path, .{ .iterate = true }) catch {
+            log.info("No checkpoint directory found", .{});
+            return false;
+        };
+        defer dir.close();
+
+        var latest_step: u64 = 0;
+        var latest_path: ?[]const u8 = null;
+
+        var iter = dir.iterate();
+        while (try iter.next()) |entry| {
+            if (entry.kind != .file) continue;
+            if (!std.mem.startsWith(u8, entry.name, "ckpt_")) continue;
+            if (!std.mem.endsWith(u8, entry.name, ".bin")) continue;
+
+            // Parse step from filename
+            const step_str = entry.name[5 .. entry.name.len - 4];
+            const step = std.fmt.parseInt(u64, step_str, 10) catch continue;
+
+            if (step > latest_step) {
+                latest_step = step;
+                if (latest_path) |p| self.allocator.free(p);
+                latest_path = try std.fmt.allocPrint(self.allocator, "{s}/{s}", .{
+                    self.base_path,
+                    entry.name,
+                });
+            }
+        }
+
+        if (latest_path) |path| {
+            defer self.allocator.free(path);
+            return try self.load(t, path);
+        }
+
+        return false;
+    }
+
+    /// Load a specific checkpoint
+    pub fn load(self: *Self, t: *trainer.MetalTrainer, path: []const u8) !bool {
+        log.info("Loading checkpoint from {s}...", .{path});
+
+        const file = std.fs.cwd().openFile(path, .{}) catch |err| {
+            log.err("Failed to open checkpoint: {}", .{err});
+            return false;
+        };
+        defer file.close();
+
+        var buffered = std.io.bufferedReader(file.reader());
+        const reader = buffered.reader();
+
+        // Read and verify header
+        var header: CheckpointHeader = undefined;
+        _ = try reader.readAll(std.mem.asBytes(&header));
+
+        if (!std.mem.eql(u8, &header.magic, MAGIC)) {
+            log.err("Invalid checkpoint magic", .{});
+            return false;
+        }
+
+        if (header.version != VERSION) {
+            log.warn("Checkpoint version mismatch: file={d}, expected={d}", .{
+                header.version,
+                VERSION,
+            });
+        }
+
+        // Verify config compatibility
+        const expected_hash = computeConfigHash(&t.config);
+        if (header.config_hash != expected_hash) {
+            log.warn("Config hash mismatch - checkpoint may be incompatible", .{});
+        }
+
+        // Load model weights
+        try self.readModelWeights(reader, &t.model);
+
+        // Load optimizer state
+        try self.readOptimizerState(reader, &t.opt_state);
+
+        // Restore training state
+        t.step = header.step;
+        t.total_tokens = header.total_tokens;
+        t.accum_step = header.accum_step;
+
+        log.info("Checkpoint loaded: step={d}, tokens={d}", .{
+            header.step,
+            header.total_tokens,
+        });
+
+        return true;
+    }
+
+    /// Read model weights from checkpoint
+    fn readModelWeights(self: *Self, reader: anytype, model: *trainer.GPT2State) !void {
+        _ = self;
+
+        // Embeddings
+        try readBuffer(reader, model.wte);
+        try readBuffer(reader, model.wpe);
+
+        // Final layer norm
+        try readBuffer(reader, model.ln_f_gamma);
+        try readBuffer(reader, model.ln_f_beta);
+
+        // LM head
+        try readBuffer(reader, model.lm_head);
+
+        // Per-layer weights
+        for (model.layers) |*layer| {
+            try readBuffer(reader, layer.ln1_gamma);
+            try readBuffer(reader, layer.ln1_beta);
+            try readBuffer(reader, layer.Wqkv);
+            try readBuffer(reader, layer.bias_qkv);
+            try readBuffer(reader, layer.Wo);
+            try readBuffer(reader, layer.bias_o);
+
+            try readBuffer(reader, layer.ln2_gamma);
+            try readBuffer(reader, layer.ln2_beta);
+            try readBuffer(reader, layer.Wfc);
+            try readBuffer(reader, layer.bias_fc);
+            try readBuffer(reader, layer.Wproj);
+            try readBuffer(reader, layer.bias_proj);
+        }
+    }
+
+    /// Read optimizer state from checkpoint
+    fn readOptimizerState(self: *Self, reader: anytype, opt: *trainer.AdamWState) !void {
+        _ = self;
+
+        // Embedding optimizer state
+        try readBuffer(reader, opt.wte_m);
+        try readBuffer(reader, opt.wte_v);
+        try readBuffer(reader, opt.wpe_m);
+        try readBuffer(reader, opt.wpe_v);
+
+        // Final LN optimizer state
+        try readBuffer(reader, opt.ln_f_gamma_m);
+        try readBuffer(reader, opt.ln_f_gamma_v);
+        try readBuffer(reader, opt.ln_f_beta_m);
+        try readBuffer(reader, opt.ln_f_beta_v);
+
+        // LM head optimizer state
+        try readBuffer(reader, opt.lm_head_m);
+        try readBuffer(reader, opt.lm_head_v);
+
+        // Per-layer optimizer state
+        for (opt.layers) |*layer| {
+            try readBuffer(reader, layer.ln1_gamma_m);
+            try readBuffer(reader, layer.ln1_gamma_v);
+            try readBuffer(reader, layer.ln1_beta_m);
+            try readBuffer(reader, layer.ln1_beta_v);
+
+            try readBuffer(reader, layer.Wqkv_m);
+            try readBuffer(reader, layer.Wqkv_v);
+            try readBuffer(reader, layer.bias_qkv_m);
+            try readBuffer(reader, layer.bias_qkv_v);
+            try readBuffer(reader, layer.Wo_m);
+            try readBuffer(reader, layer.Wo_v);
+            try readBuffer(reader, layer.bias_o_m);
+            try readBuffer(reader, layer.bias_o_v);
+
+            try readBuffer(reader, layer.ln2_gamma_m);
+            try readBuffer(reader, layer.ln2_gamma_v);
+            try readBuffer(reader, layer.ln2_beta_m);
+            try readBuffer(reader, layer.ln2_beta_v);
+
+            try readBuffer(reader, layer.Wfc_m);
+            try readBuffer(reader, layer.Wfc_v);
+            try readBuffer(reader, layer.bias_fc_m);
+            try readBuffer(reader, layer.bias_fc_v);
+            try readBuffer(reader, layer.Wproj_m);
+            try readBuffer(reader, layer.Wproj_v);
+            try readBuffer(reader, layer.bias_proj_m);
+            try readBuffer(reader, layer.bias_proj_v);
+        }
+    }
+
+    /// Cleanup old checkpoints, keeping only the most recent N
+    fn cleanupOldCheckpoints(self: *Self) !void {
+        if (self.checkpoints.items.len <= self.keep_last_n) return;
+
+        // Sort by step (oldest first)
+        std.mem.sort(CheckpointInfo, self.checkpoints.items, {}, struct {
+            fn lessThan(_: void, a: CheckpointInfo, b: CheckpointInfo) bool {
+                return a.step < b.step;
+            }
+        }.lessThan);
+
+        // Delete oldest checkpoints
+        while (self.checkpoints.items.len > self.keep_last_n) {
+            const info = self.checkpoints.orderedRemove(0);
+            std.fs.cwd().deleteFile(info.path) catch |err| {
+                log.warn("Failed to delete old checkpoint {s}: {}", .{ info.path, err });
+            };
+            self.allocator.free(info.path);
+            log.info("Deleted old checkpoint: step {d}", .{info.step});
+        }
+    }
+
+    pub fn deinit(self: *Self) void {
+        for (self.checkpoints.items) |info| {
+            self.allocator.free(info.path);
+        }
+        self.checkpoints.deinit();
+    }
+};
+
+// =============================================================================
+// Helper Functions
+// =============================================================================
+
+/// Write a Metal buffer to file (for shared storage, we can read directly)
+fn writeBuffer(writer: anytype, buffer: metal.MetalBuffer) !void {
+    const ptr = buffer.contents();
+    const slice = ptr[0..buffer.size];
+    try writer.writeAll(slice);
+}
+
+/// Read into a Metal buffer from file
+fn readBuffer(reader: anytype, buffer: metal.MetalBuffer) !void {
+    const ptr = buffer.contents();
+    const slice = ptr[0..buffer.size];
+    _ = try reader.readAll(slice);
+}
+
+/// Compute a hash of the config for compatibility checking
+fn computeConfigHash(config: *const trainer.GPT2Config) u64 {
+    var hasher = std.hash.Wyhash.init(0);
+    hasher.update(std.mem.asBytes(&config.n_layer));
+    hasher.update(std.mem.asBytes(&config.n_head));
+    hasher.update(std.mem.asBytes(&config.n_embd));
+    hasher.update(std.mem.asBytes(&config.n_ctx));
+    hasher.update(std.mem.asBytes(&config.n_vocab));
+    return hasher.final();
+}
+
+// =============================================================================
+// Auto-Save on Signal
+// =============================================================================
+
+/// Global pointer for signal handler (not great but necessary for signals)
+var global_trainer: ?*trainer.MetalTrainer = null;
+var global_checkpointer: ?*Checkpointer = null;
+
+/// Setup signal handlers for graceful shutdown
+pub fn setupSignalHandlers(t: *trainer.MetalTrainer, ckpt: *Checkpointer) void {
+    global_trainer = t;
+    global_checkpointer = ckpt;
+
+    // Note: Zig std doesn't have direct signal handling
+    // In production, use std.os.sigaction or a C interop
+    // For now, we rely on manual CTRL+C handling in the main loop
+}
+
+// =============================================================================
+// Tests
+// =============================================================================
+
+test "config hash" {
+    const config1 = trainer.GPT2Config{};
+    const config2 = trainer.GPT2Config{ .n_layer = 6 };
+
+    const hash1 = computeConfigHash(&config1);
+    const hash2 = computeConfigHash(&config2);
+
+    try std.testing.expect(hash1 != hash2);
+}

