+//! GPT-2 124M Training Entry Point
+//!
+//! Trains GPT-2 124M from scratch on OpenWebText using Metal acceleration.
+//! Target: 2.5B tokens (Chinchilla-optimal) in ~96 hours on M2 MacBook Pro.
+//!
+//! Usage:
+//!   zig build gpt2-train -Doptimize=ReleaseFast
+//!   ./zig-out/bin/gpt2-train --data data/train.zell
+//!
+//! Expected output:
+//!   Step 100 | Loss: 10.4 | 6,500 tok/s | 3.2GB VRAM
+//!   ...
+//!   Step 5208 | Loss: 3.2 | 7,850 tok/s | 3.2GB VRAM
+
+const std = @import("std");
+
+// Metal training modules
+const metal = @import("metal/metal_engine.zig");
+const MetalEngine = metal.MetalEngine;
+const data_loader = @import("data/data_loader.zig");
+const telemetry_mod = @import("telemetry.zig");
+const GPT2Trainer = @import("gpt2_trainer.zig").GPT2Trainer;
+const GPT2Config = @import("gpt2_trainer.zig").GPT2Config;
+
+const log = std.log.scoped(.gpt2_train);
+
+/// Global flag for graceful shutdown
+var running = std.atomic.Value(bool).init(true);
+
+/// Training configuration from CLI
+const TrainConfig = struct {
+    data_path: []const u8 = "data/train.zell",
+    checkpoint_dir: []const u8 = "checkpoints",
+    log_path: []const u8 = "training_log.csv",
+
+    // Model config
+    batch_size: u32 = 32,
+    grad_accum_steps: u32 = 15, // Logical batch = 32 * 15 = 480
+    context_length: u32 = 1024,
+
+    // Training config
+    target_tokens: u64 = 2_500_000_000, // 2.5B tokens
+    max_steps: u64 = 0, // 0 = unlimited, train until target_tokens
+    learning_rate: f32 = 6e-4,
+    warmup_steps: u32 = 2000,
+    weight_decay: f32 = 0.1,
+
+    // Logging and checkpointing
+    log_interval: u32 = 10,
+    checkpoint_interval: u32 = 500,
+    keep_checkpoints: u32 = 3,
+
+    // Resume
+    auto_resume: bool = true,
+};
+
+pub fn main() !void {
+    var gpa = std.heap.GeneralPurposeAllocator(.{}){};
+    defer _ = gpa.deinit();
+    const allocator = gpa.allocator();
+
+    // Parse command line arguments
+    const config = try parseArgs(allocator);
+
+    // Print banner
+    printBanner();
+
+    log.info("Configuration:", .{});
+    log.info("  Data: {s}", .{config.data_path});
+    log.info("  Batch size: {d} x {d} = {d} (logical)", .{
+        config.batch_size,
+        config.grad_accum_steps,
+        config.batch_size * config.grad_accum_steps,
+    });
+    log.info("  Target: {d}B tokens", .{config.target_tokens / 1_000_000_000});
+
+    // Initialize Metal Engine
+    log.info("Initializing Metal Engine...", .{});
+    var engine = try MetalEngine.init(allocator);
+    defer engine.deinit();
+
+    // Load Metal shaders
+    log.info("Compiling Metal shaders...", .{});
+    const shader_source = @embedFile("metal/gpt2_kernels.metal");
+    try engine.loadShaderSource(shader_source);
+
+    // Initialize Data Loader (Zero-Copy)
+    log.info("Memory-mapping dataset: {s}", .{config.data_path});
+    var loader = try data_loader.DataLoader.init(
+        allocator,
+        config.data_path,
+        &engine,
+        .{
+            .shuffle = true,
+            .seed = 42,
+            .context_length = config.context_length,
+        },
+    );
+    defer loader.deinit();
+
+    log.info("Dataset: {d} tokens ({d}M sequences)", .{
+        loader.total_tokens,
+        loader.numSequences(config.context_length) / 1_000_000,
+    });
+
+    // Initialize GPT-2 Trainer with real GPU compute
+    log.info("Initializing GPT-2 124M model with full GPU compute...", .{});
+    const model_config = GPT2Config{
+        .n_layer = 12,
+        .n_head = 12,
+        .n_embd = 768,
+        .n_ctx = config.context_length,
+        .n_vocab = 50304,
+        .batch_size = config.batch_size,
+        .grad_accum_steps = config.grad_accum_steps,
+        .learning_rate = config.learning_rate,
+        .warmup_steps = config.warmup_steps,
+        .weight_decay = config.weight_decay,
+    };
+
+    var trainer = try GPT2Trainer.init(allocator, &engine, model_config);
+    defer trainer.deinit();
+
+    // Initialize Telemetry
+    var logger = try telemetry_mod.Telemetry.init(config.log_path, .{
+        .log_interval = config.log_interval,
+        .console_output = true,
+    });
+    defer logger.deinit();
+
+    // Report memory usage
+    const mem = engine.getMemoryStats();
+    log.info("GPU Memory allocated: {d}MB ({d} buffers)", .{
+        mem.allocated_bytes / (1024 * 1024),
+        mem.buffer_count,
+    });
+
+    // Training Loop
+    log.info("Starting training (target: {d}B tokens)...", .{config.target_tokens / 1_000_000_000});
+    logger.logMilestone("Training started");
+
+    var last_checkpoint_step: u64 = trainer.step;
+    var timer = try std.time.Timer.start();
+
+    while (running.load(.monotonic)) {
+        // Get next batch from data loader
+        const batch_info = loader.nextBatchOffset(config.batch_size, config.context_length);
+
+        // Get the dataset Metal buffer for zero-copy training
+        const dataset_buffer = loader.getMetalBuffer() orelse {
+            log.err("Dataset not loaded as Metal buffer", .{});
+            return error.NoMetalBuffer;
+        };
+
+        // Forward + Backward + (maybe) Optimizer Step
+        const loss = try trainer.trainStep(dataset_buffer, batch_info.token_offset);
+
+        // Log progress
+        if (trainer.step % config.log_interval == 0 and trainer.accum_step == 0) {
+            const elapsed_ns = timer.lap();
+            const elapsed_sec = @as(f64, @floatFromInt(elapsed_ns)) / 1_000_000_000.0;
+            const tokens_this_interval = config.log_interval * config.batch_size * config.context_length * config.grad_accum_steps;
+            const tok_per_sec = @as(f64, @floatFromInt(tokens_this_interval)) / elapsed_sec;
+
+            const grad_norm: f32 = 0.0; // TODO: implement
+            try logger.logStep(
+                trainer.step,
+                loss,
+                trainer.total_tokens,
+                engine.getAllocatedBytes(),
+                trainer.getCurrentLR(),
+                grad_norm,
+                @intCast(batch_info.epoch),
+            );
+
+            // Print detailed status
+            log.info("Step {d} | Loss: {d:.4} | {d:.0} tok/s | {d}MB VRAM | LR: {d:.6}", .{
+                trainer.step,
+                loss,
+                tok_per_sec,
+                engine.getAllocatedBytes() / (1024 * 1024),
+                trainer.getCurrentLR(),
+            });
+
+            // Sync log to disk periodically
+            if (trainer.step % 100 == 0) {
+                try logger.sync();
+            }
+        }
+
+        // Checkpoint
+        if (trainer.step >= last_checkpoint_step + config.checkpoint_interval) {
+            // Simple checkpoint: save step and token count
+            try saveCheckpoint(allocator, config.checkpoint_dir, &trainer);
+            last_checkpoint_step = trainer.step;
+            logger.logMilestone("Checkpoint saved");
+        }
+
+        // Check termination conditions
+        if (trainer.total_tokens >= config.target_tokens) {
+            log.info("Target tokens reached!", .{});
+            logger.logMilestone("Target tokens reached");
+            break;
+        }
+
+        if (config.max_steps > 0 and trainer.step >= config.max_steps) {
+            log.info("Max steps reached!", .{});
+            logger.logMilestone("Max steps reached");
+            break;
+        }
+    }
+
+    // Final checkpoint
+    log.info("Saving final checkpoint...", .{});
+    try saveCheckpoint(allocator, config.checkpoint_dir, &trainer);
+
+    // Summary
+    logger.logSummary(trainer.step, trainer.total_tokens);
+
+    log.info("Training complete!", .{});
+}
+
+/// Save checkpoint
+fn saveCheckpoint(allocator: std.mem.Allocator, base_path: []const u8, trainer: *GPT2Trainer) !void {
+    // Create checkpoint directory
+    std.fs.cwd().makePath(base_path) catch |err| {
+        if (err != error.PathAlreadyExists) return err;
+    };
+
+    const path = try std.fmt.allocPrint(allocator, "{s}/ckpt_{d:0>8}.bin", .{
+        base_path,
+        trainer.step,
+    });
+    defer allocator.free(path);
+
+    log.info("Saving checkpoint to {s} (step={}, tokens={})", .{
+        path,
+        trainer.step,
+        trainer.total_tokens,
+    });
+
+    const file = try std.fs.cwd().createFile(path, .{});
+    defer file.close();
+
+    var header: [32]u8 = undefined;
+    @memcpy(header[0..8], "ZELLCKPT");
+    std.mem.writeInt(u64, header[8..16], 1, .little); // Version
+    std.mem.writeInt(u64, header[16..24], trainer.step, .little);
+    std.mem.writeInt(u64, header[24..32], trainer.total_tokens, .little);
+
+    try file.writeAll(&header);
+    log.info("Checkpoint saved", .{});
+}
+
+/// Parse command line arguments
+fn parseArgs(allocator: std.mem.Allocator) !TrainConfig {
+    var config = TrainConfig{};
+    var arg_iter = try std.process.argsWithAllocator(allocator);
+    defer arg_iter.deinit();
+
+    // Skip program name
+    _ = arg_iter.skip();
+
+    while (arg_iter.next()) |arg| {
+        if (std.mem.eql(u8, arg, "--data") or std.mem.eql(u8, arg, "-d")) {
+            config.data_path = arg_iter.next() orelse return error.MissingDataArg;
+        } else if (std.mem.eql(u8, arg, "--checkpoint-dir")) {
+            config.checkpoint_dir = arg_iter.next() orelse return error.MissingCheckpointArg;
+        } else if (std.mem.eql(u8, arg, "--log")) {
+            config.log_path = arg_iter.next() orelse return error.MissingLogArg;
+        } else if (std.mem.eql(u8, arg, "--batch-size") or std.mem.eql(u8, arg, "-b")) {
+            const val = arg_iter.next() orelse return error.MissingBatchSizeArg;
+            config.batch_size = std.fmt.parseInt(u32, val, 10) catch return error.InvalidBatchSize;
+        } else if (std.mem.eql(u8, arg, "--grad-accum")) {
+            const val = arg_iter.next() orelse return error.MissingGradAccumArg;
+            config.grad_accum_steps = std.fmt.parseInt(u32, val, 10) catch return error.InvalidGradAccum;
+        } else if (std.mem.eql(u8, arg, "--lr")) {
+            const val = arg_iter.next() orelse return error.MissingLRArg;
+            config.learning_rate = std.fmt.parseFloat(f32, val) catch return error.InvalidLR;
+        } else if (std.mem.eql(u8, arg, "--target-tokens")) {
+            const val = arg_iter.next() orelse return error.MissingTargetArg;
+            config.target_tokens = std.fmt.parseInt(u64, val, 10) catch return error.InvalidTarget;
+        } else if (std.mem.eql(u8, arg, "--max-steps")) {
+            const val = arg_iter.next() orelse return error.MissingMaxStepsArg;
+            config.max_steps = std.fmt.parseInt(u64, val, 10) catch return error.InvalidMaxSteps;
+        } else if (std.mem.eql(u8, arg, "--no-resume")) {
+            config.auto_resume = false;
+        } else if (std.mem.eql(u8, arg, "--help") or std.mem.eql(u8, arg, "-h")) {
+            printHelp();
+            std.process.exit(0);
+        }
+    }
+
+    return config;
+}
+
