+//
+// GPT-2 Training Kernels for Apple Silicon
+//
+// BF16 precision with simdgroup_matrix for AMX acceleration
+// Optimized for M2/M3 with unified memory architecture
+//
+
+#include <metal_stdlib>
+#include <metal_simdgroup_matrix>
+using namespace metal;
+
+// =============================================================================
+// BF16 Support Detection and Types
+// =============================================================================
+
+#if __METAL_VERSION__ >= 310
+#define HAS_BF16 1
+typedef bfloat bf16_t;
+typedef bfloat2 bf16x2_t;
+typedef bfloat4 bf16x4_t;
+#else
+#define HAS_BF16 0
+typedef half bf16_t;
+typedef half2 bf16x2_t;
+typedef half4 bf16x4_t;
+#endif
+
+// =============================================================================
+// Parameter Structures
+// =============================================================================
+
+struct MatMulParams {
+    uint M;          // Output rows
+    uint N;          // Output cols
+    uint K;          // Inner dimension
+    float alpha;     // Scale factor
+    float beta;      // Accumulator scale
+};
+
+struct LayerNormParams {
+    uint batch_size;
+    uint hidden_size;
+    float eps;
+};
+
+struct AttentionParams {
+    uint batch_size;
+    uint seq_len;
+    uint n_heads;
+    uint head_dim;
+    float scale;     // 1/sqrt(head_dim)
+};
+
+struct AdamWParams {
+    uint count;
+    float lr;
+    float beta1;
+    float beta2;
+    float eps;
+    float weight_decay;
+    uint step;       // For bias correction
+};
+
+struct ElementwiseParams {
+    uint count;
+    float scale;
+};
+
+struct EmbedParams {
+    uint batch_size;
+    uint seq_len;
+    uint n_vocab;
+    uint n_embd;
+};
+
+// Parameters for zero-copy embedding from mmap'd dataset
+struct EmbedDatasetParams {
+    uint batch_size;
+    uint seq_len;
+    uint n_vocab;
+    uint n_embd;
+    uint token_offset;   // Offset in tokens (not bytes) into the dataset
+};
+
+struct SoftmaxParams {
+    uint batch_size;
+    uint seq_len;
+};
+
+// =============================================================================
+// Activation Functions (Inline)
+// =============================================================================
+
+// GELU approximation: 0.5 * x * (1 + tanh(sqrt(2/pi) * (x + 0.044715 * x^3)))
+inline float gelu_f32(float x) {
+    const float sqrt_2_over_pi = 0.7978845608f;
+    const float coeff = 0.044715f;
+    float x3 = x * x * x;
+    float inner = sqrt_2_over_pi * (x + coeff * x3);
+    return 0.5f * x * (1.0f + tanh(inner));
+}
+
+inline float gelu_backward_f32(float x, float grad_out) {
+    const float sqrt_2_over_pi = 0.7978845608f;
+    const float coeff = 0.044715f;
+    float x2 = x * x;
+    float x3 = x * x2;
+    float inner = sqrt_2_over_pi * (x + coeff * x3);
+    float tanh_inner = tanh(inner);
+    float sech2 = 1.0f - tanh_inner * tanh_inner;
+    float d_inner = sqrt_2_over_pi * (1.0f + 3.0f * coeff * x2);
+    float d_gelu = 0.5f * (1.0f + tanh_inner) + 0.5f * x * sech2 * d_inner;
+    return grad_out * d_gelu;
+}
