+// =============================================================================
+// MatMul Kernels (BF16 with simdgroup_matrix)
+// =============================================================================
+
+#if HAS_BF16
+
+// Tiled BF16 MatMul using simdgroup_matrix (8x8 tiles, AMX accelerated)
+// C[M,N] = A[M,K] @ B[K,N]
+kernel void matmul_bf16(
+    device const bf16_t* A [[buffer(0)]],
+    device const bf16_t* B [[buffer(1)]],
+    device bf16_t* C [[buffer(2)]],
+    constant MatMulParams& params [[buffer(3)]],
+    uint2 gid [[threadgroup_position_in_grid]],
+    uint simd_lane [[thread_index_in_simdgroup]],
+    uint simd_group [[simdgroup_index_in_threadgroup]]
+) {
+    // Each threadgroup computes a 32x32 tile of C
+    // Using 4 simdgroups, each handling 8x8 subtiles
+
+    const uint TILE_M = 32;
+    const uint TILE_N = 32;
+    const uint TILE_K = 8;
+
+    uint row_base = gid.y * TILE_M;
+    uint col_base = gid.x * TILE_N;
+
+    // Each simdgroup handles a quadrant
+    uint sg_row = (simd_group / 2) * 16;
+    uint sg_col = (simd_group % 2) * 16;
+
+    // Accumulator matrices (2x2 grid of 8x8 tiles per simdgroup)
+    simdgroup_bfloat8x8 acc[2][2];
+    for (int i = 0; i < 2; i++) {
+        for (int j = 0; j < 2; j++) {
+            acc[i][j] = make_filled_simdgroup_matrix<bfloat, 8, 8>(0.0bf);
+        }
+    }
+
+    // Iterate over K dimension in tiles
+    for (uint k = 0; k < params.K; k += TILE_K) {
+        // Load A and B tiles into simdgroup matrices
+        simdgroup_bfloat8x8 a_tile[2];
+        simdgroup_bfloat8x8 b_tile[2];
+
+        // Load 2 rows of 8x8 A tiles
+        for (int i = 0; i < 2; i++) {
+            uint a_row = row_base + sg_row + i * 8;
+            if (a_row < params.M && k < params.K) {
+                simdgroup_load(a_tile[i], A + a_row * params.K + k, params.K);
+            }
+        }
+
+        // Load 2 cols of 8x8 B tiles
+        for (int j = 0; j < 2; j++) {
+            uint b_col = col_base + sg_col + j * 8;
+            if (k < params.K && b_col < params.N) {
+                simdgroup_load(b_tile[j], B + k * params.N + b_col, params.N);
+            }
+        }
+
+        // Accumulate: acc[i][j] += a_tile[i] @ b_tile[j]
+        for (int i = 0; i < 2; i++) {
+            for (int j = 0; j < 2; j++) {
+                simdgroup_multiply_accumulate(acc[i][j], a_tile[i], b_tile[j], acc[i][j]);
+            }
+        }
+    }
+
+    // Store results
+    for (int i = 0; i < 2; i++) {
+        for (int j = 0; j < 2; j++) {
+            uint c_row = row_base + sg_row + i * 8;
+            uint c_col = col_base + sg_col + j * 8;
+            if (c_row < params.M && c_col < params.N) {
+                simdgroup_store(acc[i][j], C + c_row * params.N + c_col, params.N);
+            }
+        }
+    }
+}
+
+// Fused MatMul + Bias + GELU: Y = GELU(X @ W + bias)
+kernel void matmul_bf16_bias_gelu(
+    device const bf16_t* X [[buffer(0)]],
+    device const bf16_t* W [[buffer(1)]],
+    device const bf16_t* bias [[buffer(2)]],
+    device bf16_t* Y [[buffer(3)]],
+    constant MatMulParams& params [[buffer(4)]],
+    uint2 gid [[thread_position_in_grid]]
+) {
+    uint row = gid.y;
+    uint col = gid.x;
+
+    if (row >= params.M || col >= params.N) return;
+
+    // Compute dot product
+    float sum = 0.0f;
+    for (uint k = 0; k < params.K; k++) {
+        sum += float(X[row * params.K + k]) * float(W[k * params.N + col]);
+    }
+
+    // Add bias and apply GELU
+    sum += float(bias[col]);
+    sum = gelu_f32(sum);
+
+    Y[row * params.N + col] = bf16_t(sum);
+}
+
+// Simple MatMul (no simdgroup, works with any dispatch)
+// Y = X @ W where X is [M, K], W is [K, N], Y is [M, N]
+kernel void matmul_bf16_simple(
+    device const bf16_t* X [[buffer(0)]],
+    device const bf16_t* W [[buffer(1)]],
+    device bf16_t* Y [[buffer(2)]],
+    constant MatMulParams& params [[buffer(3)]],
+    uint2 gid [[thread_position_in_grid]]
+) {
+    uint row = gid.y;
+    uint col = gid.x;
+
+    if (row >= params.M || col >= params.N) return;
+
+    // Compute dot product
+    float sum = 0.0f;
+    for (uint k = 0; k < params.K; k++) {
+        sum += float(X[row * params.K + k]) * float(W[k * params.N + col]);
+    }
+
+    Y[row * params.N + col] = bf16_t(sum);
+}
+
+// MatMul backward for weight gradient: dW = X^T @ dY
+kernel void matmul_backward_weight_bf16(
+    device const bf16_t* X [[buffer(0)]],      // [M, K]
+    device const bf16_t* dY [[buffer(1)]],     // [M, N]
+    device bf16_t* dW [[buffer(2)]],           // [K, N]
+    constant MatMulParams& params [[buffer(3)]],
+    uint2 gid [[thread_position_in_grid]]
+) {
+    uint k = gid.y;  // Row of dW (column of X)
+    uint n = gid.x;  // Column of dW
+
+    if (k >= params.K || n >= params.N) return;
+
+    // dW[k,n] = sum_m X[m,k] * dY[m,n]
+    float sum = 0.0f;
+    for (uint m = 0; m < params.M; m++) {
+        sum += float(X[m * params.K + k]) * float(dY[m * params.N + n]);
+    }
+
+    dW[k * params.N + n] = bf16_t(sum);
+}
+
+// MatMul backward for input gradient: dX = dY @ W^T
+kernel void matmul_backward_input_bf16(
+    device const bf16_t* dY [[buffer(0)]],     // [M, N]
+    device const bf16_t* W [[buffer(1)]],      // [K, N]
+    device bf16_t* dX [[buffer(2)]],           // [M, K]
+    constant MatMulParams& params [[buffer(3)]],
+    uint2 gid [[thread_position_in_grid]]
+) {
+    uint m = gid.y;  // Row
+    uint k = gid.x;  // Column
+
+    if (m >= params.M || k >= params.K) return;
+
+    // dX[m,k] = sum_n dY[m,n] * W[k,n]
+    float sum = 0.0f;
+    for (uint n = 0; n < params.N; n++) {
+        sum += float(dY[m * params.N + n]) * float(W[k * params.N + n]);
+    }
+
+    dX[m * params.K + k] = bf16_t(sum);
+}
+
+#endif // HAS_BF16
