+// =============================================================================
+// LayerNorm Kernels
+// =============================================================================
+
+// Forward: y = (x - mean) / sqrt(var + eps) * gamma + beta
+kernel void layernorm_forward_bf16(
+    device const bf16_t* input [[buffer(0)]],
+    device const bf16_t* gamma [[buffer(1)]],
+    device const bf16_t* beta [[buffer(2)]],
+    device bf16_t* output [[buffer(3)]],
+    device float* mean_cache [[buffer(4)]],    // Cache for backward
+    device float* rstd_cache [[buffer(5)]],    // 1/sqrt(var+eps)
+    constant LayerNormParams& params [[buffer(6)]],
+    uint gid [[thread_position_in_grid]]
+) {
+    if (gid >= params.batch_size) return;
+
+    uint offset = gid * params.hidden_size;
+
+    // Compute mean
+    float sum = 0.0f;
+    for (uint i = 0; i < params.hidden_size; i++) {
+        sum += float(input[offset + i]);
+    }
+    float mean = sum / float(params.hidden_size);
+
+    // Compute variance
+    float var_sum = 0.0f;
+    for (uint i = 0; i < params.hidden_size; i++) {
+        float diff = float(input[offset + i]) - mean;
+        var_sum += diff * diff;
+    }
+    float var = var_sum / float(params.hidden_size);
+    float rstd = rsqrt(var + params.eps);
+
+    // Cache for backward
+    mean_cache[gid] = mean;
+    rstd_cache[gid] = rstd;
+
+    // Normalize and scale
+    for (uint i = 0; i < params.hidden_size; i++) {
+        float x = float(input[offset + i]);
+        float norm = (x - mean) * rstd;
+        float y = norm * float(gamma[i]) + float(beta[i]);
+        output[offset + i] = bf16_t(y);
+    }
+}
+
+// Backward: compute dgamma, dbeta, and dx
+kernel void layernorm_backward_bf16(
+    device const bf16_t* grad_output [[buffer(0)]],
+    device const bf16_t* input [[buffer(1)]],
+    device const bf16_t* gamma [[buffer(2)]],
+    device const float* mean_cache [[buffer(3)]],
+    device const float* rstd_cache [[buffer(4)]],
+    device bf16_t* grad_input [[buffer(5)]],
+    device float* grad_gamma [[buffer(6)]],    // Accumulated atomically
+    device float* grad_beta [[buffer(7)]],
+    constant LayerNormParams& params [[buffer(8)]],
+    uint gid [[thread_position_in_grid]]
+) {
+    if (gid >= params.batch_size) return;
+
+    uint offset = gid * params.hidden_size;
+    float mean = mean_cache[gid];
+    float rstd = rstd_cache[gid];
+    float N = float(params.hidden_size);
+
+    // First pass: compute sum of grad_out * gamma and grad_out * gamma * x_norm
+    float sum1 = 0.0f;  // sum of grad * gamma
+    float sum2 = 0.0f;  // sum of grad * gamma * x_norm
+
+    for (uint i = 0; i < params.hidden_size; i++) {
+        float x = float(input[offset + i]);
+        float x_norm = (x - mean) * rstd;
+        float g = float(grad_output[offset + i]);
+        float gam = float(gamma[i]);
+
+        sum1 += g * gam;
+        sum2 += g * gam * x_norm;
+    }
+
+    // Second pass: compute grad_input
+    for (uint i = 0; i < params.hidden_size; i++) {
+        float x = float(input[offset + i]);
+        float x_norm = (x - mean) * rstd;
+        float g = float(grad_output[offset + i]);
+        float gam = float(gamma[i]);
+
+        // dx = rstd * (grad * gamma - sum1/N - x_norm * sum2/N)
+        float dx = rstd * (g * gam - sum1 / N - x_norm * sum2 / N);
+        grad_input[offset + i] = bf16_t(dx);
+    }
+}
