+// =============================================================================
+// Embedding Kernels
+// =============================================================================
+
+// Forward: lookup token and position embeddings, sum them
+kernel void embed_forward_bf16(
+    device const uint* tokens [[buffer(0)]],      // [batch, seq_len]
+    device const bf16_t* wte [[buffer(1)]],       // [vocab, embd]
+    device const bf16_t* wpe [[buffer(2)]],       // [ctx, embd]
+    device bf16_t* output [[buffer(3)]],          // [batch, seq_len, embd]
+    constant EmbedParams& params [[buffer(4)]],
+    uint3 gid [[thread_position_in_grid]]
+) {
+    uint batch = gid.z;
+    uint pos = gid.y;
+    uint embd = gid.x;
+
+    if (batch >= params.batch_size || pos >= params.seq_len || embd >= params.n_embd) return;
+
+    uint token_idx = batch * params.seq_len + pos;
+    uint token = tokens[token_idx];
+
+    // Lookup and sum
+    float tok_emb = float(wte[token * params.n_embd + embd]);
+    float pos_emb = float(wpe[pos * params.n_embd + embd]);
+
+    uint out_idx = batch * params.seq_len * params.n_embd + pos * params.n_embd + embd;
+    output[out_idx] = bf16_t(tok_emb + pos_emb);
+}
+
+// Zero-Copy Forward: reads tokens directly from mmap'd dataset (u16 format)
+// This kernel reads directly from the memory-mapped dataset file
+// The GPU reads tokens straight from SSD page cache - zero CPU copies!
+kernel void embed_forward_dataset_bf16(
+    device const ushort* dataset [[buffer(0)]],   // mmap'd dataset (u16 tokens)
+    device const bf16_t* wte [[buffer(1)]],       // [vocab, embd]
+    device const bf16_t* wpe [[buffer(2)]],       // [ctx, embd]
+    device bf16_t* output [[buffer(3)]],          // [batch, seq_len, embd]
+    constant EmbedDatasetParams& params [[buffer(4)]],
+    uint3 gid [[thread_position_in_grid]]
+) {
+    uint batch = gid.z;
+    uint pos = gid.y;
+    uint embd = gid.x;
+
+    if (batch >= params.batch_size || pos >= params.seq_len || embd >= params.n_embd) return;
+
+    // Calculate position in the dataset
+    // token_offset is the starting position for this batch
+    uint dataset_idx = params.token_offset + batch * params.seq_len + pos;
+
+    // Read u16 token directly from mmap'd memory
+    uint token = uint(dataset[dataset_idx]);
+
+    // Bounds check (should not happen with valid data)
+    if (token >= params.n_vocab) token = 0;
+
+    // Lookup and sum
+    float tok_emb = float(wte[token * params.n_embd + embd]);
+    float pos_emb = float(wpe[pos * params.n_embd + embd]);
+
+    uint out_idx = batch * params.seq_len * params.n_embd + pos * params.n_embd + embd;
+    output[out_idx] = bf16_t(tok_emb + pos_emb);
+}
+
+// Backward for zero-copy: scatter gradients back to embedding tables
+// Also reads tokens from mmap'd dataset
+kernel void embed_backward_dataset_bf16(
+    device const bf16_t* grad_output [[buffer(0)]],   // [batch, seq_len, embd]
+    device const ushort* dataset [[buffer(1)]],       // mmap'd dataset (u16 tokens)
+    device atomic_float* grad_wte [[buffer(2)]],       // [vocab, embd] - atomic for scatter
+    device atomic_float* grad_wpe [[buffer(3)]],       // [ctx, embd]
+    constant EmbedDatasetParams& params [[buffer(4)]],
+    uint3 gid [[thread_position_in_grid]]
+) {
+    uint batch = gid.z;
+    uint pos = gid.y;
+    uint embd = gid.x;
+
+    if (batch >= params.batch_size || pos >= params.seq_len || embd >= params.n_embd) return;
+
+    uint out_idx = batch * params.seq_len * params.n_embd + pos * params.n_embd + embd;
+    float grad = float(grad_output[out_idx]);
+
+    // Read token from dataset
+    uint dataset_idx = params.token_offset + batch * params.seq_len + pos;
+    uint token = uint(dataset[dataset_idx]);
+    if (token >= params.n_vocab) token = 0;
+
+    // Scatter to token embedding
+    atomic_fetch_add_explicit(&grad_wte[token * params.n_embd + embd], grad, memory_order_relaxed);
+
+    // Scatter to position embedding
+    atomic_fetch_add_explicit(&grad_wpe[pos * params.n_embd + embd], grad, memory_order_relaxed);
+}
+
+// Backward: scatter gradients back to embedding tables
+kernel void embed_backward_bf16(
+    device const bf16_t* grad_output [[buffer(0)]],   // [batch, seq_len, embd]
+    device const uint* tokens [[buffer(1)]],           // [batch, seq_len]
+    device atomic_float* grad_wte [[buffer(2)]],       // [vocab, embd] - atomic for scatter
+    device atomic_float* grad_wpe [[buffer(3)]],       // [ctx, embd]
+    constant EmbedParams& params [[buffer(4)]],
+    uint3 gid [[thread_position_in_grid]]
+) {
+    uint batch = gid.z;
+    uint pos = gid.y;
+    uint embd = gid.x;
+
+    if (batch >= params.batch_size || pos >= params.seq_len || embd >= params.n_embd) return;
+
+    uint out_idx = batch * params.seq_len * params.n_embd + pos * params.n_embd + embd;
+    float grad = float(grad_output[out_idx]);
+
+    // Scatter to token embedding
+    uint token_idx = batch * params.seq_len + pos;
+    uint token = tokens[token_idx];
+    atomic_fetch_add_explicit(&grad_wte[token * params.n_embd + embd], grad, memory_order_relaxed);
+
+    // Scatter to position embedding
+    atomic_fetch_add_explicit(&grad_wpe[pos * params.n_embd + embd], grad, memory_order_relaxed);
+}
