+    /// Get raw pointer to buffer contents (CPU-accessible for shared storage)
+    pub fn contents(self: MetalBuffer) [*]u8 {
+        return objc.bufferContents(self.handle);
+    }
+
+    /// Get typed slice of buffer contents
+    pub fn asSlice(self: MetalBuffer, comptime T: type) []T {
+        const ptr: [*]T = @ptrCast(@alignCast(self.contents()));
+        return ptr[0..self.element_count];
+    }
