+        // Get default Metal device (Apple Silicon GPU)
+        const device = objc.createSystemDefaultDevice() orelse {
+            log.err("Failed to create Metal device. Is this an Apple Silicon Mac?", .{});
+            return error.MetalDeviceNotFound;
+        };
