+        // Check cache
+        if (self.pipelines.get(kernel_name)) |pipeline| {
+            return pipeline;
+        }
+
+        // Create new pipeline
+        if (self.library == null) {
+            return error.NoLibraryLoaded;
+        }
+
+        const ns_name = objc.createNSString(kernel_name) orelse {
+            return error.StringCreationFailed;
+        };
+        defer objc.release(ns_name);
+
+        const function = objc.libraryNewFunction(self.library.?, ns_name) orelse {
+            log.err("Kernel '{s}' not found in library", .{kernel_name});
+            return error.KernelNotFound;
+        };
+        defer objc.release(function);
+
+        var err: ?objc.NSError = null;
+        const state = objc.deviceNewComputePipelineState(self.device, function, &err) orelse {
+            log.err("Failed to create pipeline for '{s}'", .{kernel_name});
+            return error.PipelineCreationFailed;
+        };
