+        const pipeline = ComputePipeline{
+            .state = state,
+            .max_threads_per_threadgroup = objc.pipelineMaxThreadsPerThreadgroup(state),
+            .thread_execution_width = objc.pipelineThreadExecutionWidth(state),
+        };
