+    // =========================================================================
+    // Memory Statistics
+    // =========================================================================
+
+    /// Get current allocated memory in bytes
+    pub fn getAllocatedBytes(self: *Self) u64 {
+        return self.allocated_bytes;
+    }
+
+    /// Get peak allocated memory in bytes
+    pub fn getPeakAllocatedBytes(self: *Self) u64 {
+        return self.peak_allocated_bytes;
+    }
+
+    /// Get number of allocated buffers
