+    // Kernel Dispatch
+    // =========================================================================
+
+    /// Dispatch a compute kernel with 1D grid
+    pub fn dispatch1D(
+        self: *Self,
+        kernel_name: []const u8,
+        buffers: []const MetalBuffer,
+        thread_count: u64,
+    ) !void {
+        const pipeline = try self.getPipeline(kernel_name);
