+        const num_groups = (thread_count + threads_per_group - 1) / threads_per_group;
+
+        const threadgroups = objc.MTLSize{ .width = num_groups, .height = 1, .depth = 1 };
+        const threads_per_threadgroup = objc.MTLSize{ .width = threads_per_group, .height = 1, .depth = 1 };
