+        const threadgroups = objc.MTLSize{ .width = groups_x, .height = groups_y, .depth = 1 };
+        const threads_per_threadgroup = objc.MTLSize{ .width = threadgroup_x, .height = threadgroup_y, .depth = 1 };
+
+        objc.encoderDispatchThreadgroups(encoder, threadgroups, threads_per_threadgroup);
+        objc.encoderEndEncoding(encoder);
+
+        objc.commandBufferCommit(cmd_buffer);
+        objc.commandBufferWaitUntilCompleted(cmd_buffer);
+    }
