+        self.batch_encoder = null;
+        self.batch_cmd_buffer = null;
+
+        log.debug("Batch completed: {} kernels", .{self.batch_kernel_count});
+        self.batch_kernel_count = 0;
+    }
+
+    /// Commit batch asynchronously (returns immediately, use waitForBatch to sync)
+    pub fn commitAsync(self: *Self) !objc.MTLCommandBuffer {
+        const encoder = self.batch_encoder orelse {
+            return error.NoBatchInProgress;
+        };
+        const cmd_buffer = self.batch_cmd_buffer orelse {
+            return error.NoBatchInProgress;
+        };
+
+        objc.encoderEndEncoding(encoder);
+        objc.commandBufferCommit(cmd_buffer);
+
+        self.batch_encoder = null;
+        self.batch_cmd_buffer = null;
+        self.batch_kernel_count = 0;
+
+        return cmd_buffer;
+    }
+
+    /// Wait for an async command buffer to complete
+    pub fn waitForBuffer(self: *Self, cmd_buffer: objc.MTLCommandBuffer) void {
+        _ = self;
+        objc.commandBufferWaitUntilCompleted(cmd_buffer);
+    }
+
+    /// Cancel current batch (discard without executing)
+    pub fn cancelBatch(self: *Self) void {
+        if (self.batch_encoder) |encoder| {
+            objc.encoderEndEncoding(encoder);
+        }
+        self.batch_encoder = null;
+        self.batch_cmd_buffer = null;
+        self.batch_kernel_count = 0;
+    }
+
+    // =========================================================================
+    // Convenience: Auto-batched dispatch
+    // =========================================================================
+
+    /// Dispatch that automatically batches - use beginBatch/commitAndWait for explicit control
+    /// or this for automatic batching within a scope
+    pub fn dispatchThreadsAsync(
+        self: *Self,
+        kernel_name: []const u8,
+        buffers: []const MetalBuffer,
+        params: ?*const anyopaque,
+        params_size: u64,
+        threads_x: u64,
+        threads_y: u64,
+        threads_z: u64,
+    ) !void {
+        // Start batch if not already started
+        if (self.batch_cmd_buffer == null) {
+            try self.beginBatch();
+        }
+
+        try self.enqueueKernel(kernel_name, buffers, params, params_size, threads_x, threads_y, threads_z);
+    }
+
+    /// Synchronize all pending async dispatches
+    pub fn synchronize(self: *Self) !void {
+        if (self.batch_cmd_buffer != null) {
+            try self.commitAndWait();
+        }
+    }
+};
+
+// =============================================================================
