+//! Streaming Inference Engine
+//!
+//! Heterogeneous pipelining for running massive models on limited RAM.
+//! Uses CPU for JIT decompression while GPU computes in parallel.
+//!
+//! Architecture:
+//! ┌─────────────────────────────────────────────────────────────────┐
+//! │                    STREAMING INFERENCE                          │
+//! ├─────────────────────────────────────────────────────────────────┤
+//! │  RAM (Compressed)     CPU (Decompress)    GPU (Compute)         │
+//! │  ┌─────────────┐     ┌─────────────┐    ┌─────────────┐        │
+//! │  │ Layer 0 2bit│────▶│ Decompress  │───▶│ Buffer A    │        │
+//! │  │ Layer 1 2bit│     │ Thread      │    │ (BF16)      │        │
+//! │  │ Layer 2 2bit│     └─────────────┘    └──────┬──────┘        │
+//! │  │    ...      │            │                   │               │
+//! │  │ Layer N 2bit│     ┌──────▼──────┐    ┌──────▼──────┐        │
+//! │  └─────────────┘     │ Decompress  │───▶│ Buffer B    │        │
+//! │                      │ Thread      │    │ (BF16)      │        │
+//! │                      └─────────────┘    └──────┬──────┘        │
+//! │                                                │               │
+//! │                                         ┌──────▼──────┐        │
+//! │                                         │ Persistent  │        │
+//! │                                         │ GPU Kernel  │        │
+//! │                                         └─────────────┘        │
+//! └─────────────────────────────────────────────────────────────────┘
+//!
+//! The CPU decompresses layer N+1 while GPU computes layer N.
+//! This hides decompression latency completely.
+
+const std = @import("std");
+const metal = @import("metal/metal_engine.zig");
+const MetalEngine = metal.MetalEngine;
+const MetalBuffer = metal.MetalBuffer;
+const objc = @import("metal/objc.zig");
+const bf16 = @import("metal/bf16_utils.zig");
+const BF16 = bf16.BF16;
+
+const log = std.log.scoped(.streaming_engine);
+
+// =============================================================================
+// Ring Buffer Control (Shared between CPU and GPU)
+// =============================================================================
+
+/// Buffer status for lock-free synchronization
+pub const BufferStatus = enum(u32) {
+    empty = 0,        // CPU can write
+    ready = 1,        // GPU can read
+    processing = 2,   // GPU is reading
+    done = 3,         // GPU finished, CPU can reclaim
+};
+
+/// Control structure shared between CPU decompressor and GPU kernel
+/// This lives in shared memory accessible by both CPU and GPU
+pub const RingControl = extern struct {
+    // Buffer A status
+    buffer_a_status: u32 align(4),
+    buffer_a_layer: u32,
+
+    // Buffer B status
+    buffer_b_status: u32 align(4),
+    buffer_b_layer: u32,
+
+    // Global state
+    current_layer: u32,
+    total_layers: u32,
+    should_stop: u32,
+    error_code: u32,
+
+    // Timing stats
+    gpu_compute_ns: u64,
+    cpu_decompress_ns: u64,
+
+    const Self = @This();
+
+    pub fn init(total_layers: u32) Self {
+        return Self{
+            .buffer_a_status = @intFromEnum(BufferStatus.empty),
+            .buffer_a_layer = 0,
+            .buffer_b_status = @intFromEnum(BufferStatus.empty),
+            .buffer_b_layer = 0,
+            .current_layer = 0,
+            .total_layers = total_layers,
+            .should_stop = 0,
+            .error_code = 0,
+            .gpu_compute_ns = 0,
+            .cpu_decompress_ns = 0,
+        };
+    }
+};
+
+// =============================================================================
+// Compression Formats
+// =============================================================================
+
+/// Compression method for weights
+pub const CompressionType = enum(u8) {
+    none = 0,           // Raw BF16 (baseline)
+    int8 = 1,           // 8-bit quantization
+    int4 = 2,           // 4-bit quantization (standard)
+    int2 = 3,           // 2-bit quantization (aggressive)
+    huffman = 4,        // Huffman coded (variable length)
+    lz4 = 5,            // LZ4 block compression
+    custom = 6,         // Custom proprietary format
+};
+
+/// Header for compressed layer data
+pub const CompressedLayerHeader = extern struct {
+    magic: [4]u8,           // "ZLYR"
+    version: u16,
+    compression: u8,
+    reserved: u8,
+    compressed_size: u64,
+    decompressed_size: u64,
+    checksum: u32,
+    scale: f32,             // Quantization scale
+    zero_point: f32,        // Quantization zero point
+};
+
+// =============================================================================
+// Ping-Pong Buffer Manager
+// =============================================================================
+
+/// Manages the double-buffered ping-pong system
+pub const PingPongBuffers = struct {
+    allocator: std.mem.Allocator,
+    engine: *MetalEngine,
+
+    // The two alternating buffers
+    buffer_a: MetalBuffer,
+    buffer_b: MetalBuffer,
+
+    // Control structure (in shared memory)
+    control_buffer: MetalBuffer,
+    control: *RingControl,
+
+    // Size of each buffer (one layer decompressed)
+    layer_size: u64,
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator, engine: *MetalEngine, layer_size: u64, total_layers: u32) !Self {
+        log.info("Initializing ping-pong buffers: {}MB per buffer", .{layer_size / (1024 * 1024)});
+
+        // Allocate the two layer buffers
+        const buffer_a = try engine.createBuffer(BF16, layer_size / @sizeOf(BF16));
+        const buffer_b = try engine.createBuffer(BF16, layer_size / @sizeOf(BF16));
+
+        // Allocate control structure in shared memory
+        const control_buffer = try engine.createBuffer(RingControl, 1);
+        const control_ptr = control_buffer.asSlice(RingControl);
+        control_ptr[0] = RingControl.init(total_layers);
+
+        return Self{
+            .allocator = allocator,
+            .engine = engine,
+            .buffer_a = buffer_a,
+            .buffer_b = buffer_b,
+            .control_buffer = control_buffer,
+            .control = &control_ptr[0],
+            .layer_size = layer_size,
+        };
+    }
+
+    /// Get pointer to buffer A for CPU writing
+    pub fn getBufferA(self: *Self) []BF16 {
+        return self.buffer_a.asSlice(BF16);
+    }
+
+    /// Get pointer to buffer B for CPU writing
+    pub fn getBufferB(self: *Self) []BF16 {
+        return self.buffer_b.asSlice(BF16);
+    }
+
+    /// Check if buffer A is empty (safe for CPU to write)
+    pub fn isBufferAEmpty(self: *Self) bool {
+        return @atomicLoad(&self.control.buffer_a_status, .acquire) == @intFromEnum(BufferStatus.empty);
+    }
+
+    /// Check if buffer B is empty
+    pub fn isBufferBEmpty(self: *Self) bool {
+        return @atomicLoad(&self.control.buffer_b_status, .acquire) == @intFromEnum(BufferStatus.empty);
+    }
+
+    /// Mark buffer A as ready for GPU
+    pub fn markBufferAReady(self: *Self, layer: u32) void {
+        self.control.buffer_a_layer = layer;
+        @atomicStore(&self.control.buffer_a_status, @intFromEnum(BufferStatus.ready), .release);
+    }
+
+    /// Mark buffer B as ready for GPU
+    pub fn markBufferBReady(self: *Self, layer: u32) void {
+        self.control.buffer_b_layer = layer;
+        @atomicStore(&self.control.buffer_b_status, @intFromEnum(BufferStatus.ready), .release);
+    }
+
+    /// Signal GPU to stop
+    pub fn signalStop(self: *Self) void {
+        @atomicStore(&self.control.should_stop, 1, .release);
+    }
+
+    pub fn deinit(self: *Self) void {
+        MetalEngine.releaseBuffer(self.buffer_a);
+        MetalEngine.releaseBuffer(self.buffer_b);
+        MetalEngine.releaseBuffer(self.control_buffer);
+    }
+};
+
+// =============================================================================
+// CPU Decompressor Thread
+// =============================================================================
+
+/// Decompressor running on CPU in background thread
+pub const Decompressor = struct {
+    allocator: std.mem.Allocator,
+    buffers: *PingPongBuffers,
+
+    // Compressed model data (mmap'd from disk)
+    compressed_data: []const u8,
+    layer_offsets: []const u64,  // Offset to each compressed layer
+
+    // Threading
+    thread: ?std.Thread,
+    running: std.atomic.Value(bool),
+
+    // Stats
+    total_decompressed: u64,
+    decompress_time_ns: u64,
+
+    const Self = @This();
+
+    pub fn init(
+        allocator: std.mem.Allocator,
+        buffers: *PingPongBuffers,
+        compressed_data: []const u8,
+        layer_offsets: []const u64,
+    ) Self {
+        return Self{
+            .allocator = allocator,
+            .buffers = buffers,
+            .compressed_data = compressed_data,
+            .layer_offsets = layer_offsets,
+            .thread = null,
+            .running = std.atomic.Value(bool).init(false),
+            .total_decompressed = 0,
+            .decompress_time_ns = 0,
+        };
+    }
+
+    /// Start the decompressor thread
+    pub fn start(self: *Self) !void {
+        self.running.store(true, .release);
+        self.thread = try std.Thread.spawn(.{}, decompressLoop, .{self});
+    }
+
+    /// Stop the decompressor thread
+    pub fn stop(self: *Self) void {
+        self.running.store(false, .release);
+        if (self.thread) |t| {
+            t.join();
+        }
+    }
+
+    /// Main decompression loop (runs on CPU thread)
+    fn decompressLoop(self: *Self) void {
+        log.info("Decompressor thread started", .{});
+
+        var layer: u32 = 0;
+        var use_buffer_a = true;
+
+        while (self.running.load(.acquire) and layer < self.buffers.control.total_layers) {
+            // Wait for target buffer to be empty
+            if (use_buffer_a) {
+                while (!self.buffers.isBufferAEmpty()) {
+                    if (!self.running.load(.acquire)) return;
+                    std.atomic.spinLoopHint();
+                }
+            } else {
+                while (!self.buffers.isBufferBEmpty()) {
+                    if (!self.running.load(.acquire)) return;
+                    std.atomic.spinLoopHint();
+                }
+            }
+
+            // Decompress this layer
+            const start_time = std.time.nanoTimestamp();
+
+            const dest = if (use_buffer_a)
+                self.buffers.getBufferA()
+            else
+                self.buffers.getBufferB();
+
+            self.decompressLayer(layer, dest);
+
+            const elapsed = std.time.nanoTimestamp() - start_time;
+            self.decompress_time_ns += @intCast(elapsed);
+            self.total_decompressed += dest.len * @sizeOf(BF16);
+
+            // Mark buffer as ready for GPU
+            if (use_buffer_a) {
+                self.buffers.markBufferAReady(layer);
+            } else {
+                self.buffers.markBufferBReady(layer);
+            }
+
+            // Alternate buffers
+            use_buffer_a = !use_buffer_a;
+            layer += 1;
+        }
+
+        log.info("Decompressor finished: {} layers, {}MB total, {}ms avg/layer", .{
+            layer,
+            self.total_decompressed / (1024 * 1024),
+            if (layer > 0) (self.decompress_time_ns / layer) / 1_000_000 else 0,
+        });
+    }
+
+    /// Decompress a single layer
+    fn decompressLayer(self: *Self, layer: u32, dest: []BF16) void {
+        const offset = self.layer_offsets[layer];
+        const header_ptr: *const CompressedLayerHeader = @ptrCast(@alignCast(self.compressed_data.ptr + offset));
+
+        const compressed_start = offset + @sizeOf(CompressedLayerHeader);
+        const compressed = self.compressed_data[compressed_start..compressed_start + header_ptr.compressed_size];
+
+        switch (@as(CompressionType, @enumFromInt(header_ptr.compression))) {
+            .none => {
+                // No compression - direct copy
+                const src: []const BF16 = @as([*]const BF16, @ptrCast(@alignCast(compressed.ptr)))[0..dest.len];
+                @memcpy(dest, src);
+            },
+            .int8 => {
+                // 8-bit quantization
+                decompressInt8(compressed, dest, header_ptr.scale, header_ptr.zero_point);
+            },
+            .int4 => {
+                // 4-bit quantization (2 values per byte)
+                decompressInt4(compressed, dest, header_ptr.scale, header_ptr.zero_point);
+            },
+            .int2 => {
+                // 2-bit quantization (4 values per byte)
+                decompressInt2(compressed, dest, header_ptr.scale, header_ptr.zero_point);
+            },
+            .lz4 => {
