+// =============================================================================
+// Decompression Functions
+// =============================================================================
+
+/// Decompress 8-bit quantized weights to BF16
+fn decompressInt8(compressed: []const u8, dest: []BF16, scale: f32, zero_point: f32) void {
+    for (compressed, 0..) |byte, i| {
