+
+/// Decompress 4-bit quantized weights to BF16 (2 values per byte)
+fn decompressInt4(compressed: []const u8, dest: []BF16, scale: f32, zero_point: f32) void {
+    var dest_idx: usize = 0;
+    for (compressed) |byte| {
+        // Low 4 bits
+        if (dest_idx >= dest.len) break;
+        const low: i8 = @as(i8, @intCast(byte & 0x0F)) - 8;  // Signed 4-bit
+        dest[dest_idx] = bf16.f32ToBf16((@as(f32, @floatFromInt(low)) - zero_point) * scale);
+        dest_idx += 1;
+
+        // High 4 bits
+        if (dest_idx >= dest.len) break;
+        const high: i8 = @as(i8, @intCast((byte >> 4) & 0x0F)) - 8;
+        dest[dest_idx] = bf16.f32ToBf16((@as(f32, @floatFromInt(high)) - zero_point) * scale);
+        dest_idx += 1;
+    }
+}
+
+/// Decompress 2-bit quantized weights to BF16 (4 values per byte)
+fn decompressInt2(compressed: []const u8, dest: []BF16, scale: f32, zero_point: f32) void {
+    // 2-bit values: 0, 1, 2, 3 → mapped to -1.5, -0.5, 0.5, 1.5
+    const lookup: [4]f32 = .{ -1.5, -0.5, 0.5, 1.5 };
+
+    var dest_idx: usize = 0;
+    for (compressed) |byte| {
+        // 4 values packed per byte
+        inline for (0..4) |shift| {
+            if (dest_idx >= dest.len) break;
+            const bits: u2 = @truncate((byte >> (shift * 2)));
+            const value = (lookup[bits] - zero_point) * scale;
+            dest[dest_idx] = bf16.f32ToBf16(value);
+            dest_idx += 1;
+        }
+    }
+}
+
+/// Decompress LZ4 block to BF16
+/// LZ4 block format: sequence of [token][literals][match]
+/// Token: 4 bits literal length + 4 bits match length
+/// If length == 15, read additional bytes until < 255
+fn decompressLZ4(compressed: []const u8, dest: []BF16) void {
+    if (compressed.len == 0) {
+        @memset(dest, bf16.BF16_ZERO);
+        return;
+    }
+
+    // Output buffer as bytes for LZ4 decompression
+    const dest_bytes: []u8 = @as([*]u8, @ptrCast(dest.ptr))[0 .. dest.len * @sizeOf(BF16)];
+    var dest_pos: usize = 0;
+    var src_pos: usize = 0;
+
+    while (src_pos < compressed.len and dest_pos < dest_bytes.len) {
+        // Read token
+        const token = compressed[src_pos];
+        src_pos += 1;
+
+        var literal_len: usize = token >> 4;
+        const match_len_base: usize = token & 0x0F;
+
+        // Extended literal length
+        if (literal_len == 15) {
+            while (src_pos < compressed.len) {
+                const extra = compressed[src_pos];
+                src_pos += 1;
+                literal_len += extra;
+                if (extra != 255) break;
+            }
+        }
+
+        // Copy literals
+        if (literal_len > 0 and src_pos + literal_len <= compressed.len) {
+            const copy_len = @min(literal_len, dest_bytes.len - dest_pos);
+            @memcpy(dest_bytes[dest_pos..][0..copy_len], compressed[src_pos..][0..copy_len]);
+            src_pos += literal_len;
+            dest_pos += copy_len;
+        }
+
+        // Check for end of block
+        if (src_pos >= compressed.len or dest_pos >= dest_bytes.len) break;
+
+        // Read match offset (2 bytes, little endian)
+        if (src_pos + 2 > compressed.len) break;
+        const offset: usize = @as(usize, compressed[src_pos]) | (@as(usize, compressed[src_pos + 1]) << 8);
+        src_pos += 2;
+
+        if (offset == 0 or offset > dest_pos) {
+            // Invalid offset - corruption or end of data
+            break;
+        }
+
+        // Calculate match length (min 4)
+        var match_len: usize = match_len_base + 4;
+
+        // Extended match length
+        if (match_len_base == 15) {
+            while (src_pos < compressed.len) {
+                const extra = compressed[src_pos];
+                src_pos += 1;
+                match_len += extra;
+                if (extra != 255) break;
+            }
+        }
+
+        // Copy match (may overlap - copy byte by byte)
+        const match_start = dest_pos - offset;
+        const copy_len = @min(match_len, dest_bytes.len - dest_pos);
+
+        for (0..copy_len) |i| {
+            dest_bytes[dest_pos + i] = dest_bytes[match_start + (i % offset)];
+        }
+        dest_pos += copy_len;
+    }
+
+    // Zero remaining if any
+    if (dest_pos < dest_bytes.len) {
+        @memset(dest_bytes[dest_pos..], 0);
+    }
+}
+
+/// LZ4 compression for testing (simple implementation)
+pub fn compressLZ4(src: []const u8, dest: []u8) usize {
+    if (src.len == 0) return 0;
+
+    var dest_pos: usize = 0;
+    var src_pos: usize = 0;
+
+    // Simple literal-only compression for small data
+    // Full LZ4 would use hash table for match finding
+    while (src_pos < src.len) {
+        const remaining = src.len - src_pos;
+        const chunk = @min(remaining, 255 + 15); // Max per token
+
+        if (dest_pos + 1 + chunk >= dest.len) break;
+
+        // Token: literal length only (no match)
+        if (chunk <= 15) {
+            dest[dest_pos] = @intCast(chunk << 4);
+            dest_pos += 1;
+        } else {
+            dest[dest_pos] = 0xF0; // 15 << 4
+            dest_pos += 1;
+            var extra = chunk - 15;
+            while (extra >= 255) {
+                dest[dest_pos] = 255;
+                dest_pos += 1;
+                extra -= 255;
+            }
+            dest[dest_pos] = @intCast(extra);
+            dest_pos += 1;
+        }
+
+        // Copy literals
+        @memcpy(dest[dest_pos..][0..chunk], src[src_pos..][0..chunk]);
+        dest_pos += chunk;
+        src_pos += chunk;
+
+        // Last sequence has no match
+        if (src_pos >= src.len) break;
+
+        // Add dummy match offset (required by format except last sequence)
+        if (dest_pos + 2 < dest.len and src_pos < src.len) {
+            dest[dest_pos] = 0;
+            dest[dest_pos + 1] = 0;
+            dest_pos += 2;
+        }
+    }
+
+    return dest_pos;
+}
