+//! Training Telemetry Logger
+//!
+//! Generates CSV logs for training metrics and console output.
+//! This provides the "proof" for the benchmark.
+//!
+//! Output Format (training_log.csv):
+//! step,loss,tokens_per_sec,vram_mb,total_tokens,lr,grad_norm,epoch
+//!
+//! Console Output:
+//! Step 100 | Loss: 4.2100 | 7,850 tok/s | 3.2GB VRAM | 3.2M tokens
+
+const std = @import("std");
+const log = std.log.scoped(.telemetry);
+
+/// Training telemetry logger
+pub const Telemetry = struct {
+    file: std.fs.File,
+    start_time: i64,
+    last_log_time: i64,
+    last_tokens: u64,
+
+    // Running statistics
+    total_loss: f64,
+    loss_count: u64,
+    min_loss: f32,
+    max_tokens_per_sec: f64,
+
+    // Configuration
+    log_interval: u32, // Log every N steps
+    console_output: bool,
+
+    const Self = @This();
+
+    /// Initialize telemetry logger
+    pub fn init(path: []const u8, options: TelemetryOptions) !Self {
+        const file = try std.fs.cwd().createFile(path, .{});
+        errdefer file.close();
+
+        // Write CSV header
+        try file.writeAll("step,loss,tokens_per_sec,vram_mb,total_tokens,lr,grad_norm,epoch,elapsed_sec\n");
+
+        const now = std.time.milliTimestamp();
+
+        log.info("Telemetry initialized: {s}", .{path});
+
+        return Self{
+            .file = file,
+            .start_time = now,
+            .last_log_time = now,
+            .last_tokens = 0,
+            .total_loss = 0,
+            .loss_count = 0,
+            .min_loss = std.math.inf(f32),
+            .max_tokens_per_sec = 0,
+            .log_interval = options.log_interval,
+            .console_output = options.console_output,
+        };
+    }
+
+    /// Log a training step
+    pub fn logStep(
+        self: *Self,
+        step: u64,
+        loss: f32,
+        total_tokens: u64,
+        vram_bytes: u64,
+        learning_rate: f32,
+        grad_norm: f32,
+        epoch: u32,
+    ) !void {
+        const now = std.time.milliTimestamp();
+        const elapsed_ms = now - self.last_log_time;
+        const total_elapsed_sec = @divFloor(now - self.start_time, 1000);
+
+        // Calculate tokens per second
+        const delta_tokens = total_tokens - self.last_tokens;
+        const tps: f64 = if (elapsed_ms > 0)
+            @as(f64, @floatFromInt(delta_tokens)) / (@as(f64, @floatFromInt(elapsed_ms)) / 1000.0)
+        else
+            0;
+
+        // Update statistics
+        self.total_loss += loss;
+        self.loss_count += 1;
+        if (loss < self.min_loss) self.min_loss = loss;
+        if (tps > self.max_tokens_per_sec) self.max_tokens_per_sec = tps;
+
+        // Update tracking
+        self.last_log_time = now;
+        self.last_tokens = total_tokens;
+
+        const vram_mb = vram_bytes / (1024 * 1024);
+
+        // Write CSV row
+        var buf: [256]u8 = undefined;
+        const line = try std.fmt.bufPrint(&buf, "{d},{d:.4},{d:.1},{d},{d},{d:.6},{d:.4},{d},{d}\n", .{
+            step,
+            loss,
+            tps,
+            vram_mb,
+            total_tokens,
+            learning_rate,
+            grad_norm,
+            epoch,
+            total_elapsed_sec,
+        });
+        try self.file.writeAll(line);
+
+        // Console output
+        if (self.console_output) {
+            const tokens_str = formatTokens(total_tokens);
+            const eta = self.estimateETA(total_tokens, tps);
+
+            std.debug.print(
+                "\x1b[2K\rStep {d: >6} | Loss: {d:.4} | {d: >6.0} tok/s | {d: >4}MB | {s: >8} tokens | ETA: {s}",
+                .{ step, loss, tps, vram_mb, tokens_str, eta },
+            );
+        }
+    }
+
+    /// Log a milestone (epoch complete, checkpoint saved, etc.)
+    pub fn logMilestone(self: *Self, message: []const u8) void {
+        if (self.console_output) {
+            std.debug.print("\n\x1b[32m[MILESTONE]\x1b[0m {s}\n", .{message});
+        }
