+
+        const hours = @divFloor(total_time_sec, 3600);
+        const mins = @divFloor(@mod(total_time_sec, 3600), 60);
+        const secs = @mod(total_time_sec, 60);
+
+        if (self.console_output) {
+            std.debug.print("\n\n", .{});
+            std.debug.print("╔══════════════════════════════════════════════════════╗\n", .{});
+            std.debug.print("║              TRAINING COMPLETE                       ║\n", .{});
+            std.debug.print("╠══════════════════════════════════════════════════════╣\n", .{});
+            std.debug.print("║  Total Steps:      {d: >10}                       ║\n", .{final_step});
+            std.debug.print("║  Total Tokens:     {s: >10}                       ║\n", .{formatTokens(final_tokens)});
+            std.debug.print("║  Training Time:    {d: >3}h {d: >2}m {d: >2}s                      ║\n", .{ hours, mins, secs });
+            std.debug.print("║  Avg Loss:         {d: >10.4}                       ║\n", .{avg_loss});
+            std.debug.print("║  Min Loss:         {d: >10.4}                       ║\n", .{self.min_loss});
+            std.debug.print("║  Peak Throughput:  {d: >10.0} tok/s                ║\n", .{self.max_tokens_per_sec});
+            std.debug.print("╚══════════════════════════════════════════════════════╝\n", .{});
+        }
+
+        log.info("Training complete: {d} steps, {} tokens, {d}h {d}m {d}s", .{
+            final_step,
+            final_tokens,
+            hours,
+            mins,
+            secs,
+        });
+    }
+
+    /// Estimate remaining time
+    fn estimateETA(self: *Self, current_tokens: u64, current_tps: f64) []const u8 {
+        const TARGET_TOKENS: u64 = 2_500_000_000; // 2.5B
+
+        if (current_tps <= 0 or current_tokens >= TARGET_TOKENS) {
+            return "---";
+        }
+
+        const remaining_tokens = TARGET_TOKENS - current_tokens;
+        const remaining_sec: u64 = @intFromFloat(@as(f64, @floatFromInt(remaining_tokens)) / current_tps);
+
+        _ = self;
+
+        // Return static string based on remaining time
+        if (remaining_sec > 86400 * 7) return ">7d";
+        if (remaining_sec > 86400 * 3) return "3-7d";
+        if (remaining_sec > 86400) return "1-3d";
+        if (remaining_sec > 3600 * 12) return "12-24h";
+        if (remaining_sec > 3600 * 6) return "6-12h";
+        if (remaining_sec > 3600) return "1-6h";
+        if (remaining_sec > 1800) return "30-60m";
+        if (remaining_sec > 600) return "10-30m";
+        return "<10m";
+    }
+
+    /// Sync to disk (call periodically to prevent data loss)
+    pub fn sync(self: *Self) !void {
+        try self.file.sync();
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.file.close();
+    }
+};
