+    } else if (tokens >= 1_000_000) {
+        const m = @as(f64, @floatFromInt(tokens)) / 1_000_000.0;
+        return std.fmt.bufPrint(&Static.buf, "{d:.1}M", .{m}) catch "?M";
+    } else if (tokens >= 1_000) {
+        const k = @as(f64, @floatFromInt(tokens)) / 1_000.0;
+        return std.fmt.bufPrint(&Static.buf, "{d:.1}K", .{k}) catch "?K";
+    } else {
+        return std.fmt.bufPrint(&Static.buf, "{d}", .{tokens}) catch "?";
+    }
+}
