+// =============================================================================
+// Progress Bar
+// =============================================================================
+
+/// Simple progress bar for long operations
+pub const ProgressBar = struct {
+    total: u64,
+    current: u64,
+    width: u32,
+    label: []const u8,
+    start_time: i64,
+
+    pub fn init(total: u64, label: []const u8) ProgressBar {
+        return .{
+            .total = total,
+            .current = 0,
+            .width = 40,
+            .label = label,
+            .start_time = std.time.milliTimestamp(),
+        };
+    }
+
+    pub fn update(self: *ProgressBar, current: u64) void {
+        self.current = current;
+        self.render();
+    }
+
+    pub fn increment(self: *ProgressBar, delta: u64) void {
+        self.current += delta;
+        self.render();
+    }
+
+    fn render(self: *ProgressBar) void {
+        const progress = @as(f64, @floatFromInt(self.current)) / @as(f64, @floatFromInt(self.total));
+        const filled: u32 = @intFromFloat(progress * @as(f64, @floatFromInt(self.width)));
+        const empty = self.width - filled;
+
+        std.debug.print("\r{s} [", .{self.label});
+        for (0..filled) |_| std.debug.print("█", .{});
+        for (0..empty) |_| std.debug.print("░", .{});
+        std.debug.print("] {d:.1}%", .{progress * 100});
+    }
+
+    pub fn finish(self: *ProgressBar) void {
+        self.current = self.total;
+        self.render();
+        const elapsed = std.time.milliTimestamp() - self.start_time;
+        std.debug.print(" Done! ({d}ms)\n", .{elapsed});
+    }
+};
