+// =============================================================================
+// Memory Tracking
+// =============================================================================
+
+/// Track memory usage for telemetry
+pub const MemoryTracker = struct {
+    peak_usage: u64 = 0,
+    current_usage: u64 = 0,
+
+    pub fn update(self: *MemoryTracker, usage: u64) void {
+        self.current_usage = usage;
+        if (usage > self.peak_usage) {
+            self.peak_usage = usage;
+        }
+    }
+
+    pub fn getCurrent(self: *MemoryTracker) u64 {
+        return self.current_usage;
+    }
+
+    pub fn getPeak(self: *MemoryTracker) u64 {
+        return self.peak_usage;
+    }
+};
